// // This D flip-flop captures the value of the input 'd' on the falling edge of the clock signal 'clk'. The output 'q' is a register with a configurable width, defined by the parameter 'size', which defaults to 64 bits.
module top_module(
output reg [size-1:0]	q,
input [size-1:0]	d,
input clk
);parameter size = 128;

always @(posedge clk) begin
	   q <= d;
end

endmodule
